import React, { useEffect, useState } from "react";
import { MapContainer, TileLayer, Marker, Popup } from "react-leaflet";
import L from "leaflet";
import { fetchBuses } from "./api"; // Fixed import
import BusCharts from "./BusCharts";
import Alerts from "./Alerts";
import "./BusMap.css"; // Fixed case

const ghostIcon = new L.Icon({
  iconUrl: "https://cdn-icons-png.flaticon.com/512/616/616408.png",
  iconSize: [30, 30],
});

const normalIcon = new L.Icon({
  iconUrl: "https://cdn-icons-png.flaticon.com/512/854/854878.png",
  iconSize: [30, 30],
});

const BusMap = () => {
  const [buses, setBuses] = useState([]);
  const [showCharts, setShowCharts] = useState(false);
  const [alerts, setAlerts] = useState([]);

  const getBusData = async () => {
    try {
      const data = await fetchBuses();
      setBuses(data);

      // Detect ghost buses for alert
      const newAlerts = data
        .filter((bus) => bus.status === "Ghost")
        .map((bus) => `Ghost bus detected: ${bus.id}`);
      setAlerts(newAlerts);
    } catch (error) {
      console.error("Error fetching buses:", error);
    }
  };

  useEffect(() => {
    getBusData();
    const interval = setInterval(getBusData, 120000); // Fetch every 2 minutes
    return () => clearInterval(interval);
  }, []);

  return (
    <div>
      <div className="map-controls">
        <button onClick={() => setShowCharts(!showCharts)}>
          {showCharts ? "Hide Charts" : "Show Charts"}
        </button>
      </div>

      <MapContainer
        center={[40.7128, -74.006]}
        zoom={12}
        style={{ height: "600px", width: "100%" }}
      >
        <TileLayer
          url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" // Plain white-ish map
          attribution='&copy; <a href="http://osm.org/copyright">OpenStreetMap</a>'
        />
        {buses.map((bus) => (
          <Marker
            key={bus.id}
            position={[bus.lat, bus.lon]}
            icon={bus.status === "Ghost" ? ghostIcon : normalIcon}
          >
            <Popup>
              Bus ID: {bus.id} <br /> Status: {bus.status}
            </Popup>
          </Marker>
        ))}
      </MapContainer>

      {showCharts && <BusCharts buses={buses} />}

      {alerts.length > 0 && <Alerts alerts={alerts} />}
    </div>
  );
};

export default BusMap;
